const body = $input.first().json.body || $input.first().json;

const type = body.type || 'system';
const title = (body.title || '\uC54C\uB9BC').replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]));
const summary = (body.summary || '').replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]));
const source = body.source || '';
const sourceId = body.sourceId || '';
const nextAction = body.nextAction || '';
const chatId = String(body.chatId || '7713811206');

const TYPE_MAP = {
  task: ['\u{1F4CB}', '\uC5C5\uBB34'],
  prd: ['\u{1F4DD}', '\uAE30\uD68D\uC548'],
  briefing: ['\u2600\uFE0F', '\uBE0C\uB9AC\uD551'],
  data: ['\u{1F4CA}', '\uB370\uC774\uD130'],
  system: ['\u2699\uFE0F', '\uC2DC\uC2A4\uD15C'],
  dev: ['\u{1F4BB}', '\uAC1C\uBC1C'],
  approval: ['\u2705', '\uC2B9\uC778']
};

const [icon, label] = TYPE_MAP[type] || ['\u2699\uFE0F', type];

const parts = [];
parts.push(`${icon} <b>[${label}]</b> ${title}`);
parts.push('');

if (summary) {
  parts.push(summary.split('\n').slice(0, 3).join('\n'));
  parts.push('');
}

const meta = [];
if (source) meta.push(`\u{1F4CD} ${source}`);
if (sourceId) meta.push(`\u{1F517} ${sourceId}`);
if (meta.length) parts.push(meta.join(' | '));

if (nextAction) {
  parts.push(`\u{1F449} ${nextAction}`);
}

return [{ json: { message: parts.join('\n'), chatId } }];
